CREATE VIEW `ads_srsv_log_user_grace_period_log_view` (`product_id` COMMENT "产品id", `id` COMMENT "主键id", `user_id` COMMENT "用户id", `order_id` COMMENT "订单id", `item_id` COMMENT "itemid", `pay_type` COMMENT "googleplay /appstore", `merchandise_type` COMMENT "810: SVIP 840：新福利包，850：VIP", `grace_period_begin_time` COMMENT "宽限期开始时间", `grace_period_end_time` COMMENT "宽限期结束时间", `order_renew_time` COMMENT " 订单续订时间", `record_type` COMMENT "记录类型 0 进入宽限期 1 订单续订", `create_time` COMMENT "创建时间", `app_id` COMMENT "应用id", `amount` COMMENT "金额(税前)", `base_amount` COMMENT "金额(税后)", `vip_type` COMMENT "订阅周期（海剧：1、月卡 2、季卡 3、年卡 4、周卡）（海阅：1、月卡 3、季卡 12、年卡 107、周卡）", `vip_type_name` COMMENT "订阅周期名称", `sr_createtime` COMMENT "starrocks数据注入时间", `sr_updatetime` COMMENT "starrocks数据更新时间") AS SELECT 6833 AS `product_id`, `ods`.`a`.`Id`, `ods`.`a`.`UserId`, `ods`.`a`.`OrderId`, `ods`.`a`.`ItemId`, `ods`.`a`.`PayType`, `ods`.`a`.`MerchandiseType`, `ods`.`a`.`GracePeriodBeginTime`, `ods`.`a`.`GracePeriodEndTime`, if(`ods`.`a`.`RecordType` = 1, `ods`.`a`.`OrderRenewTime`, NULL) AS `if(a.RecordType = 1, a.OrderRenewTime, NULL)`, `ods`.`a`.`RecordType`, `ods`.`a`.`CreateTime`, `ods`.`a`.`AppId`, `ods`.`d`.`Amount` / 100 AS `d.Amount / 100`, `ods`.`d`.`BaseAmount` / 100 AS `d.BaseAmount / 100`, ifnull(`ads`.`b`.`vip_type`, `c`.`vip_type`) AS `ifnull(b.vip_type, c.vip_type)`, `c`.`vip_type_name`, `ods`.`a`.`sr_createtime`, `ods`.`a`.`sr_updatetime`
FROM `ods`.`ods_tidb_short_video_user_grace_period_log` AS `a` LEFT OUTER JOIN `ads`.`ads_bi_short_video_trade_user_subscribe_di` AS `b` ON `ods`.`a`.`OrderId` = `ads`.`b`.`order_id` LEFT OUTER JOIN (SELECT `dim`.`dim_short_video_goods_view`.`item_id`, `dim`.`dim_short_video_goods_view`.`shop_item_id`, `dim`.`dim_short_video_goods_view`.`vip_type`, CASE WHEN (`dim`.`dim_short_video_goods_view`.`vip_type` = 1) THEN '月卡' WHEN (`dim`.`dim_short_video_goods_view`.`vip_type` = 2) THEN '季卡' WHEN (`dim`.`dim_short_video_goods_view`.`vip_type` = 3) THEN '年卡' WHEN (`dim`.`dim_short_video_goods_view`.`vip_type` = 4) THEN '周卡' END AS `vip_type_name`
FROM `dim`.`dim_short_video_goods_view`
WHERE (`dim`.`dim_short_video_goods_view`.`shop_item_id` IN (840, 810)) AND (`dim`.`dim_short_video_goods_view`.`is_remove` = 0)
GROUP BY 1, 2, 3) `c` ON (`ads`.`b`.`item_id` = `c`.`item_id`) AND (`ads`.`b`.`shop_item` = `c`.`shop_item_id`) LEFT OUTER JOIN `ods`.`ods_tidb_sharpenginepaycenter_hk_payorder` AS `d` ON `ods`.`a`.`OrderId` = `ods`.`d`.`OrderSerialId` UNION ALL SELECT `ods`.`a`.`product_id`, `ods`.`a`.`Id`, `ods`.`a`.`UserId`, `ods`.`a`.`OrderId`, `ods`.`a`.`ItemId`, `ods`.`a`.`PayType`, `ods`.`a`.`MerchandiseType`, `ods`.`a`.`GracePeriodBeginTime`, `ods`.`a`.`GracePeriodEndTime`, if(`ods`.`a`.`RecordType` = 1, `ods`.`a`.`OrderRenewTime`, NULL) AS `if(a.RecordType = 1, a.OrderRenewTime, NULL)`, `ods`.`a`.`RecordType`, `ods`.`a`.`CreateTime`, `ods`.`a`.`AppId`, `ods`.`d`.`Amount` / 100 AS `d.Amount / 100`, `ods`.`d`.`BaseAmount` / 100 AS `d.BaseAmount / 100`, `c`.`validity`, `c`.`vip_type_name`, `ods`.`a`.`sr_createtime`, `ods`.`a`.`sr_updatetime`
FROM `ods`.`ods_tidb_readerlog_xx_Log_UserGracePeriodLog` AS `a` LEFT OUTER JOIN `ads`.`ads_bi_trade_user_subscribe_di` AS `b` ON `ods`.`a`.`OrderId` = `ads`.`b`.`order_id` LEFT OUTER JOIN (SELECT `dim`.`dim_trade_pay_item_info_view`.`item_id`, `dim`.`dim_trade_pay_item_info_view`.`validity`, CASE WHEN (`dim`.`dim_trade_pay_item_info_view`.`validity` = 1) THEN '月卡' WHEN (`dim`.`dim_trade_pay_item_info_view`.`validity` = 3) THEN '季卡' WHEN (`dim`.`dim_trade_pay_item_info_view`.`validity` = 12) THEN '年卡' WHEN (`dim`.`dim_trade_pay_item_info_view`.`validity` = 107) THEN '周卡' END AS `vip_type_name`
FROM `dim`.`dim_trade_pay_item_info_view`
WHERE (((`dim`.`dim_trade_pay_item_info_view`.`merchandise_type` IN (800, 810, 830, 840, 850)) AND (`dim`.`dim_trade_pay_item_info_view`.`status` = 1)) AND (`dim`.`dim_trade_pay_item_info_view`.`is_delete` = 0)) AND (`dim`.`dim_trade_pay_item_info_view`.`product_id` != 3399)
GROUP BY 1, 2) `c` ON `ads`.`b`.`item_id` = `c`.`item_id` LEFT OUTER JOIN `ods`.`ods_tidb_sharpenginepaycenter_hk_payorder` AS `d` ON `ods`.`a`.`OrderId` = `ods`.`d`.`OrderSerialId`;